-- ────────────────────────────────────────────────────────────────
-- v4.1.3 demo enrichment — generated by enrich/gen.py
-- Seeds: persona-driven comorbidities (~50/72), 4-12 historical
--        completed encounters per patient (clinical depth: vitals,
--        ICD-10, Rx, lab orders + resulted values), allergies fill-in,
--        and 16 new today encounters for V skewed for visible queue.
-- Idempotent: encounter_number uses suffix V412.
--             Re-running deletes prior V412 content first.
-- ────────────────────────────────────────────────────────────────
BEGIN;

-- 0. Clean prior v412 enrichment so this is re-runnable
DELETE FROM prescriptions WHERE encounter_id IN (SELECT id FROM encounters WHERE encounter_number LIKE '%-V412');
DELETE FROM lab_results WHERE lab_order_id IN (SELECT id FROM lab_orders WHERE encounter_id IN (SELECT id FROM encounters WHERE encounter_number LIKE '%-V412'));
DELETE FROM lab_orders WHERE encounter_id IN (SELECT id FROM encounters WHERE encounter_number LIKE '%-V412');
DELETE FROM encounters WHERE encounter_number LIKE '%-V412';

